def generate_random_date(start_days_ago, end_days_ago):
    """Generate a random date between start_days_ago and end_days_ago."""
    now = timezone.now().date()
    days_ago = random.randint(start_days_ago, end_days_ago)
    return now - datetime.timedelta(days=days_ago)

