    def generate_invoice_number_for_migration(issue_date, existing_numbers):
        date_str = issue_date.strftime("%Y%m%d")
        shuffled_date = ''.join(random.sample(date_str, len(date_str)))
        for _ in range(10):
            sequence = f"{random.randint(0, 9999):04d}"
            invoice_number = f"DJP-{shuffled_date}-{sequence}"
            if invoice_number not in existing_numbers:
                existing_numbers.add(invoice_number)
                return invoice_number
        raise ValueError("Failed to generate unique invoice number during migration")

    # Create sample invoices with optional payments
